EMBED_MODEL = "nomic-embed-text"
VECTOR_STORE = "clanka_memory.json"
IGNORE_DIRS = {'.git', '.venv', '__pycache__', 'build', 'clanka.egg-info', 'node_modules'}

def get_embedding(text):
    """Pings local Ollama to turn text into a 768-dimensional math vector."""
    try:
        response = ollama.embeddings(model=EMBED_MODEL, prompt=text)
        return response['embedding']
    except Exception as e:
        print(f"[!] Embedding failed: {e}")
        return None

def cosine_similarity(vec_a, vec_b):
    """The raw math to find how closely two vectors match."""
    dot_product = np.dot(vec_a, vec_b)
    norm_a = np.linalg.norm(vec_a)
    norm_b = np.linalg.norm(vec_b)
    if norm_a == 0 or norm_b == 0:
        return 0.0
    return dot_product / (norm_a * norm_b)

def build_index(directory="."):
    """Scans files, chunks them, and saves their embeddings to JSON."""
    print(f"[*] Clanka is indexing '{directory}'...")
    memory = []

    for root, dirs, files in os.walk(directory):
        # Strip out bloat directories in-place
        dirs[:] = [d for d in dirs if d not in IGNORE_DIRS and not d.startswith('.')]

        for file in files:
            if not file.endswith(('.py', '.md', '.txt', '.sh', '.toml')):
                continue

            filepath = Path(root) / file
            try:
                content = filepath.read_text(errors='ignore')
                # Simple chunking: Split by double newlines (functions/paragraphs)
                chunks = [c.strip() for c in content.split('\n\n') if len(c.strip()) > 40]

                for chunk in chunks:
                    vec = get_embedding(chunk)
                    if vec:
                        memory.append({
                            "file": str(filepath),
                            "content": chunk,
                            "vector": vec
                        })
            except Exception as e:
                print(f"[dim]Skipped {filepath}: {e}[/dim]")

